import{_ as l,o as r,c as o,ag as i}from"./chunks/framework.CQYuu_FX.js";const c=JSON.parse('{"title":"会計・POSレジ","description":"","frontmatter":{"title":"会計・POSレジ"},"headers":[],"relativePath":"tenant/08-cashier.md","filePath":"tenant/08-cashier.md"}'),a={name:"tenant/08-cashier.md"};function n(s,t,d,e,g,h){return r(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="_8-会計・posレジ" tabindex="-1">8. 会計・POSレジ <a class="header-anchor" href="#_8-会計・posレジ" aria-label="Permalink to &quot;8. 会計・POSレジ&quot;">​</a></h1><p>POSレジでは、店内注文やテイクアウト注文の会計、割引、個別会計、領収書、返金、レジ開閉を行います。現金が動く操作では、担当スタッフのPIN入力が必要です。</p><div class="tip custom-block"><p class="custom-block-title">推奨端末</p><p>POSレジはAndroidタブレット + Google Chrome最新版を <strong>標準環境</strong> としています。PC + Chrome最新版でもご利用いただけます。iPad/Safariはレシート印刷の挙動が不安定なためサポート対象外です。</p></div><h2 id="会計・決済の運用" tabindex="-1">会計・決済の運用 <a class="header-anchor" href="#会計・決済の運用" aria-label="Permalink to &quot;会計・決済の運用&quot;">​</a></h2><p>POSLAでは、お客様自身がスマートフォンで決済する「POSLA決済」と、スタッフがレジ端末で操作する「通常レジ会計」を分けて運用します。</p><p>通常レジ会計では、店舗がすでに契約しているカード端末・QR決済・電子マネー・現金をそのまま使います。POSLAは決済を実行せず、支払い方法、支払い詳細、会計完了の記録だけを残します。</p><h3 id="セルフ決済とレジ決済の使い分け" tabindex="-1">セルフ決済とレジ決済の使い分け <a class="header-anchor" href="#セルフ決済とレジ決済の使い分け" aria-label="Permalink to &quot;セルフ決済とレジ決済の使い分け&quot;">​</a></h3><table tabindex="0"><thead><tr><th>決済方法</th><th>特徴・制限</th><th>推奨シーン</th></tr></thead><tbody><tr><td><strong>POSLA決済</strong></td><td>セルフ会計・テイクアウトで、Stripe Connect 経由のオンライン決済を行います。個別会計には対応していません。</td><td>スムーズな退店、事前決済、テイクアウトの取り置き。</td></tr><tr><td><strong>通常レジ会計</strong></td><td>現金、店舗のカード端末、店舗契約のQR決済・電子マネーで支払いを受け、POSLAには記録だけ残します。</td><td>店頭会計、個別会計、既存決済契約をそのまま使う場合。</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">責務の境界</p><p>お客様のスマートフォン画面（セルフ決済）には、常に「その時点で未払いの商品すべて」の合計金額が表示されます。レジで一部の商品を精算すると、セルフ決済の対象金額も自動的に減算されます。</p></div><h2 id="会計の基本手順" tabindex="-1">会計の基本手順 <a class="header-anchor" href="#会計の基本手順" aria-label="Permalink to &quot;会計の基本手順&quot;">​</a></h2><ol><li>POSレジ画面を開きます。</li><li>会計するテーブルまたは注文を選びます。</li><li>注文内容、数量、割引、合計金額を確認します。</li><li>支払い方法と支払い詳細を選びます。</li><li>必要に応じて担当スタッフのPINを入力します。</li><li>会計を完了し、レシートまたは領収書を発行します。</li></ol><p>左側の会計待ちテーブル一覧では、着席から60分以上経過した未会計テーブルに「会計注意」、90分以上経過した未会計テーブルに「長時間」表示が出ます。混雑時の声かけや締め漏れ防止に使ってください。</p><h2 id="支払い方法" tabindex="-1">支払い方法 <a class="header-anchor" href="#支払い方法" aria-label="Permalink to &quot;支払い方法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>支払い方法</th><th>確認事項</th></tr></thead><tbody><tr><td>現金</td><td>預かり金、お釣り、ドロア操作を確認してください。</td></tr><tr><td>クレジットカード / デビット</td><td>店舗の外部カード端末で決済を完了してから、POSLAで「カード」と詳細を選び、会計記録を確定してください。</td></tr><tr><td>QR決済 / 電子マネー</td><td>店舗契約のQR決済アプリ・端末・電子マネー端末で支払い完了を確認してから、POSLAで「QR」と詳細を選び、会計記録を確定してください。</td></tr></tbody></table><h3 id="支払い詳細の記録" tabindex="-1">支払い詳細の記録 <a class="header-anchor" href="#支払い詳細の記録" aria-label="Permalink to &quot;支払い詳細の記録&quot;">​</a></h3><p>通常レジでは、支払い方法を選ぶと詳細選択が表示されます。</p><table tabindex="0"><thead><tr><th>大分類</th><th>詳細例</th></tr></thead><tbody><tr><td>カード</td><td>クレジット、デビット、その他カード</td></tr><tr><td>QR / 電子マネー</td><td>PayPay、楽天ペイ、d払い、au PAY、メルペイ、交通系IC、iD、QUICPay、その他</td></tr></tbody></table><p>この詳細は、取引履歴、領収書、管理画面のレジ分析「支払い詳細別」に反映されます。</p><p>カード・QR・電子マネーでは、必要に応じて外部決済端末の控え番号、端末番号、承認番号などを「控え番号・端末番号メモ」に入力できます。入力内容は取引履歴と管理画面のレジ分析に残ります。未入力の外部決済は、レジ締め前チェックで確認対象になります。</p><h2 id="個別会計" tabindex="-1">個別会計 <a class="header-anchor" href="#個別会計" aria-label="Permalink to &quot;個別会計&quot;">​</a></h2><p>同じテーブル内で別々に支払う場合は、個別会計を利用します。お客様から「品目ごとに分けて支払いたい」と要望があった場合は、レジ端末で <strong>Partial（個別）モード</strong> を有効にし、精算する品目を選択してください。</p><p>対象商品、数量、割引の適用範囲を確認してから会計してください。</p><h2 id="返金" tabindex="-1">返金 <a class="header-anchor" href="#返金" aria-label="Permalink to &quot;返金&quot;">​</a></h2><p>返金は金額と理由を確認し、店舗責任者のルールに従って実施してください。返金後は、レジ締め時の差額確認も行ってください。</p><h2 id="レジ開閉" tabindex="-1">レジ開閉 <a class="header-anchor" href="#レジ開閉" aria-label="Permalink to &quot;レジ開閉&quot;">​</a></h2><p>営業開始時にレジを開け、営業中の現金移動を記録し、営業終了時にレジを閉めます。POSLAのレジ開閉は「現金を数える作業」と「誰が操作したかの記録」を分けずに残すため、締め時の原因調査がしやすくなります。</p><h3 id="レジ開け" tabindex="-1">レジ開け <a class="header-anchor" href="#レジ開け" aria-label="Permalink to &quot;レジ開け&quot;">​</a></h3><p>開店時は、右上の <strong>【レジ開閉】</strong> からレジを開きます。現場で迷わないよう、よく使う操作は大きなボタンで選べます。</p><table tabindex="0"><thead><tr><th>操作</th><th>使う場面</th></tr></thead><tbody><tr><td><strong>前回締め現金でレジ開け</strong></td><td>前日の締め現金をそのまま釣銭準備金として使う場合</td></tr><tr><td><strong>0円で開始</strong></td><td>現金を置かずに営業開始する場合、またはキャッシュレス中心で現金を別管理する場合</td></tr><tr><td><strong>詳細に数えて開始</strong></td><td>紙幣・硬貨の枚数を数えて、開始時在高を正確に残したい場合</td></tr></tbody></table><p>詳細入力では、紙幣・硬貨の枚数を入力すると開始時在高が自動計算されます。手入力した開始時在高、金種内訳、担当スタッフPIN、メモはレジログに残ります。</p><div class="warning custom-block"><p class="custom-block-title">PINと出勤打刻</p><p>レジ開けには担当スタッフPINが必要です。PINを入力するスタッフは、先に個人アカウントでログインし、出勤打刻を済ませてください。共有アカウントでの操作は監査ログの意味がなくなるため禁止です。</p></div><h3 id="営業中の現金移動" tabindex="-1">営業中の現金移動 <a class="header-anchor" href="#営業中の現金移動" aria-label="Permalink to &quot;営業中の現金移動&quot;">​</a></h3><p>釣銭補充、現金回収、小口購入など、会計以外で現金が増減した場合は <strong>【レジ開閉】</strong> の現金移動画面で記録します。</p><table tabindex="0"><thead><tr><th>クイック操作</th><th>意味</th></tr></thead><tbody><tr><td><strong>釣銭補充</strong></td><td>両替した小銭や紙幣をレジへ足す</td></tr><tr><td><strong>現金回収</strong></td><td>売上金の一部を金庫へ移す</td></tr><tr><td><strong>両替持出</strong></td><td>両替のために一時的に現金を持ち出す</td></tr><tr><td><strong>両替戻し</strong></td><td>両替後の現金をレジへ戻す</td></tr><tr><td><strong>小口購入</strong></td><td>店舗営業に必要な少額購入をレジ現金から支払う</td></tr><tr><td><strong>消耗品購入</strong></td><td>レジ現金で消耗品を購入した場合</td></tr><tr><td><strong>記録漏れ修正</strong></td><td>釣銭補充や現金回収の記録漏れを後から補正する</td></tr></tbody></table><p>金額・理由・担当スタッフPINが記録されます。入力欄を開いて任意の金額を入れることもできますが、日常運用ではクイック操作を使うと入力ミスを減らせます。</p><h3 id="レジ締め" tabindex="-1">レジ締め <a class="header-anchor" href="#レジ締め" aria-label="Permalink to &quot;レジ締め&quot;">​</a></h3><p>閉店時は <strong>【レジ開閉】</strong> から締めます。POSLAは、開始時在高、現金会計、入金、出金、取消、返金をもとに <strong>予想現金</strong> を表示します。レジ内の実際現金と比べ、差額がある場合は理由を残します。</p><p>締め画面では、問題がなければ <strong>【問題なければこのまま締める】</strong> を使えます。未処理や確認事項がある場合は、<strong>【詳細に確認して締める】</strong> を開き、現金、外部決済、メモを確認してから締めます。</p><table tabindex="0"><thead><tr><th>確認項目</th><th>見る理由</th></tr></thead><tbody><tr><td>未会計の注文</td><td>会計漏れのまま閉店しないため</td></tr><tr><td>会計取消・返金</td><td>取消理由、返金理由、現金返却の有無を確認するため</td></tr><tr><td>外部決済控えメモ未入力</td><td>カード端末・QRアプリ側の控えとPOSLA記録を突合するため</td></tr><tr><td>予想現金と実際現金の差額</td><td>釣銭ミス、現金移動記録漏れ、会計ミスを見つけるため</td></tr><tr><td>締め後の追加操作</td><td>締めた後に会計や取消が入っていないか確認するため</td></tr><tr><td>閉店引き継ぎメモ</td><td>翌日の店長・レジ担当が状況を追えるようにするため</td></tr></tbody></table><p>締め後の記録は、管理画面の <strong>レポート → レジ分析</strong> に残ります。現金差額、支払い方法別売上、支払い詳細別、外部決済控え、現金移動、領収書再発行履歴、閉店引き継ぎメモを後から確認できます。</p><div class="tip custom-block"><p class="custom-block-title">レジ締めの考え方</p><p>POSLAは「細かく入力させるためのレジ」ではなく、「必要な時だけ詳細を残せるレジ」です。問題がなければクイック締め、差額や確認事項がある時だけ詳細確認に進む運用が基本です。</p></div><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>会計対象が出てこない</td><td>注文が提供済みになっているか確認してください。</td></tr><tr><td>金額が合わない</td><td>注文内容、割引、個別会計、返金履歴を確認してください。</td></tr><tr><td>決済端末が反応しない</td><td>POSLAではなく店舗契約の決済端末・QRアプリ側を確認してください。POSLAには完了後の記録だけ残します。</td></tr><tr><td>PINが通らない</td><td>出勤打刻、PIN設定、入力ミスを確認してください。</td></tr><tr><td>通常会計ボタンが押せない (黄色バナー)</td><td><strong>緊急レジモード</strong> を使ってください (下記)</td></tr></tbody></table><h2 id="緊急レジモード-通信障害時の会計記録" tabindex="-1">緊急レジモード (通信障害時の会計記録) <a class="header-anchor" href="#緊急レジモード-通信障害時の会計記録" aria-label="Permalink to &quot;緊急レジモード (通信障害時の会計記録)&quot;">​</a></h2><p>通信が不安定な時・POSLA の通常会計が使えない時に、<strong>会計した事実を端末内に記録して後から POSLA へ同期する</strong> モードです。</p><div class="danger custom-block"><p class="custom-block-title">この機能が代替するのは「記録」だけです</p><ul><li>POSLA がカード決済を代替するわけではありません。<strong>カード決済は必ず外部決済端末 (Airpay / Square / 電子決済端末等) で処理してください。</strong></li><li>POSLA には <strong>カード番号・有効期限・セキュリティコードを絶対に入力しないでください</strong>。入力欄そのものを用意していません。</li><li>緊急レジで記録した会計は「POSLA 未同期」です。通常の売上レポートには、管理者が確認してから反映されます。</li></ul></div><h3 id="いつ使うか" tabindex="-1">いつ使うか <a class="header-anchor" href="#いつ使うか" aria-label="Permalink to &quot;いつ使うか&quot;">​</a></h3><ul><li>レジ画面上部に黄色いバナー「古いデータを表示中」が出て、通常会計ボタンが押せない時</li><li>通常会計を押したら「通信エラー」「最新の注文状態を取得できませんでした」と出た時</li><li>お店の Wi-Fi / モバイル回線が不安定で、会計だけは記録を残したい時</li></ul><h3 id="起動方法" tabindex="-1">起動方法 <a class="header-anchor" href="#起動方法" aria-label="Permalink to &quot;起動方法&quot;">​</a></h3><p>レジ画面ヘッダ右上の 🔴 <strong>「緊急レジ」</strong> ボタンを押してください。</p><ul><li>バッジ (赤丸の中の数字) が出ている時は、未同期の緊急会計がその件数ぶん端末内に残っています。</li><li>通常運用でも店長判断で手動起動できます (検証・訓練用)。</li></ul><h3 id="使える支払方法" tabindex="-1">使える支払方法 <a class="header-anchor" href="#使える支払方法" aria-label="Permalink to &quot;使える支払方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>選択肢</th><th>意味</th></tr></thead><tbody><tr><td><strong>現金</strong></td><td>お客様から現金を受領済み。受領額とお釣りを入力</td></tr><tr><td><strong>外部カード端末</strong></td><td>決済端末 (Airpay 等) でカード決済を完了させてから、控え番号 / 承認番号を記録</td></tr><tr><td><strong>外部 QR / 電子決済</strong></td><td>外部の QR 決済端末 / 電子マネー端末で完了させてから記録</td></tr><tr><td><strong>その他外部決済</strong></td><td>上記以外 (商品券、ポイント充当、店舗判断の特殊処理等)。メモで詳細を残す</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">カード決済の流れ</p><ol><li><strong>お客様のカードは外部決済端末に通す (POSLA では処理しない)</strong></li><li>外部端末で承認 → 承認番号・控え番号が出る</li><li>外部端末の <strong>控えを必ず保管</strong> (紙 or 写真)</li><li>POSLA の「緊急レジ」で支払方法 = 「外部カード端末」を選び、控え番号 / 承認番号を記録</li><li>通信復帰後、POSLA 側で自動同期される</li></ol></div><h3 id="記録後の画面" tabindex="-1">記録後の画面 <a class="header-anchor" href="#記録後の画面" aria-label="Permalink to &quot;記録後の画面&quot;">​</a></h3><p>記録すると「POSLA 未同期の緊急会計控え」が画面に表示されます。これには:</p><ul><li>緊急会計番号 (端末内一意 ID)</li><li>テーブル名 / 合計金額 / 支払方法</li><li>外部端末の控え番号・承認番号 (入力した場合)</li><li>担当者名 / 記録時刻</li></ul><p>印刷ボタンで紙に残すこともできます。<strong>この控えは「POSLA 未同期」と明示されている点が、通常のレシートとの違いです。</strong></p><h3 id="未同期件数の確認と同期" tabindex="-1">未同期件数の確認と同期 <a class="header-anchor" href="#未同期件数の確認と同期" aria-label="Permalink to &quot;未同期件数の確認と同期&quot;">​</a></h3><ul><li>ヘッダの 🔴 ボタン横のバッジ = <strong>未同期 + 要確認件数の合計</strong><ul><li><code>3</code> のように数字だけ → 未同期のみ</li><li><code>!3</code> のように <code>!</code> 付き → <strong>要確認の会計が含まれています</strong>。管理者に連絡してください</li><li>tooltip (長押し / マウスホバー) で「未同期: N 件 / 要確認: M 件」の内訳表示</li></ul></li><li>🔴 ボタン → 「未同期会計一覧」で状態を確認</li><li>状態の意味: <ul><li><strong>未送信</strong> (<code>pending_sync</code>, オレンジ): 端末にあり、まだ送信していない状態</li><li><strong>送信中</strong> (<code>syncing</code>, 水色): 同期を試している状態</li><li><strong>同期済み</strong> (<code>synced</code>, 緑): 正常に反映された状態</li><li><strong>要確認: 重複の可能性</strong> (<code>conflict</code>, 赤): 同じ注文が通常会計でも処理されている可能性があります。<strong>管理者確認必須</strong></li><li><strong>要確認: 差異あり</strong> (<code>pending_review</code>, 紫): 金額や内容に差異があり、手動確認が必要です</li><li><strong>送信失敗</strong> (<code>failed</code>, 濃赤): 通信エラー等で送信できていません。同期再試行を行ってください</li></ul></li></ul><h3 id="未同期会計があるときにやってはいけないこと" tabindex="-1">未同期会計があるときにやってはいけないこと <a class="header-anchor" href="#未同期会計があるときにやってはいけないこと" aria-label="Permalink to &quot;未同期会計があるときにやってはいけないこと&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">未同期の間は絶対やらないでください</p><ul><li>❌ ブラウザのキャッシュ削除</li><li>❌ ブラウザデータ削除</li><li>❌ ログアウト</li><li>❌ POSLA アプリの再インストール</li><li>❌ 端末の初期化</li></ul><p>→ これらをすると <strong>ブラウザ内の保存データが消え、未同期の会計記録が復元できなくなる</strong> おそれがあります。</p><p>通信復帰後、未同期件数が 0 になってから行ってください。</p></div><h3 id="通信復帰後の確認" tabindex="-1">通信復帰後の確認 <a class="header-anchor" href="#通信復帰後の確認" aria-label="Permalink to &quot;通信復帰後の確認&quot;">​</a></h3><ol><li>通信が復帰すると自動で同期が試みられます (上部の緑バナー「通信が復帰しました」)</li><li>🔴 ボタンのバッジが 0 になれば同期完了</li><li>0 にならない件がある場合は、🔴 → 「未同期会計一覧」で状態を確認</li><li>要確認の会計が残っている場合は、<strong>管理者に連絡</strong>して精査してもらってください</li></ol><h3 id="管理者-「緊急会計台帳」で確認する" tabindex="-1">管理者: 「緊急会計台帳」で確認する <a class="header-anchor" href="#管理者-「緊急会計台帳」で確認する" aria-label="Permalink to &quot;管理者: 「緊急会計台帳」で確認する&quot;">​</a></h3><p>店長・オーナーの方は、管理画面で店舗単位の緊急会計を一覧確認し、判断記録を残せます。</p><p><strong>場所</strong>: 管理画面 → レポート → 緊急会計台帳</p><p><strong>見える内容</strong>:</p><ul><li>期間フィルタ（開始日 / 終了日、最大 92 日）</li><li>状態フィルタ（すべて / 同期済み / 要確認 / 送信失敗 など）</li><li>集計カード: 件数・合計金額・要確認件数・PIN 未確認件数・判断状況の内訳</li><li>一覧表（日付時刻 / 状態 / 判断 / テーブル / 金額 / 支払方法 / 外部端末控え番号 / 担当者 / PIN 確認状況 / 判断者・判断日時 / 備考）</li><li>行をクリックすると詳細画面（明細 / 関連注文 / メモ / 管理者判断）</li></ul><div class="warning custom-block"><p class="custom-block-title">現時点でできること / できないこと</p><ul><li>✅ 管理者判断の<strong>記録</strong>: 「有効確認 / 重複扱い / 無効扱い / 保留」ボタンで判断を残せます (詳細は次節)</li><li>❌ <strong>売上レポートへの反映</strong>: 判断を記録しても、売上レポートには自動反映されません</li><li>❌ <strong>修正・取消</strong>: 一度記録した「確定判断 (有効確認 / 重複扱い / 無効扱い)」は、その場では変更できません</li><li>要確認の会計があれば、<strong>外部決済端末の控え</strong>（レシート紙・端末画面）と必ず突き合わせてから判断してください</li><li>カード決済の真偽は POSLA では確定できません。外部端末の承認記録が正です</li></ul></div><p><strong>よくあるケース</strong>:</p><ul><li>すでに通常会計で処理済みだった → 緊急会計側を無効扱いにするか確認</li><li>別端末で同じ注文を記録していた → どちらを正とするか管理者が判断</li><li>テーブルを選ばずに手入力で記録していた → 外部端末控えと突き合わせて精査</li><li>PIN 入力後に送信失敗していた → 担当者本人へ確認</li></ul><h3 id="通常会計も取り消せます" tabindex="-1">通常会計も取り消せます <a class="header-anchor" href="#通常会計も取り消せます" aria-label="Permalink to &quot;通常会計も取り消せます&quot;">​</a></h3><p>POS レジ（<code>kds/cashier.html</code>）から普段どおりに行った会計も、取引履歴パネルから管理者が論理取消できます。誤会計の <strong>記録だけを無効化</strong>する操作で、調理や卓状態は動かしません。</p><p><strong>操作手順</strong>:</p><ol><li>POS レジ &gt; 右上「取引履歴」ボタンで取引ジャーナルを開く</li><li>対象行の右側に表示される <strong>「会計取消」</strong> ボタンを押す（表示条件は下記）</li><li><strong>取消理由（必須）</strong> を入力して実行</li></ol><p><strong>取消ボタンが表示される条件</strong>:</p><ul><li>まだ取消していない</li><li>まだ返金していない</li><li>分割会計ではない</li><li>外部決済サービスを通していない会計である <ul><li>対象の支払方法: 現金 / 手入力カード / 手入力 QR</li><li>対象外: Stripe Connect 経由のカード決済など（返金で対応）</li></ul></li><li>対象の注文種別: 店内注文 / ハンディ注文 / <strong>POS レジで会計したテイクアウト</strong><ul><li>対象外: オンライン決済済みテイクアウト（オンラインで決済完了しているもの）</li></ul></li></ul><p><strong>取消後の挙動</strong>:</p><ul><li>取引履歴: 「✗ 取消済」赤バッジが表示され、取消分を差し引いた合計が表示されます</li><li>現金の場合のみ: レジ分析に現金返却分の記録が自動で追加され、期待残高に反映されます</li><li>売上レポート: 取消済みの会計は集計から除外されます</li><li>注文状態そのものは変更されません。卓状態・レシート・KDS 表示もそのままです</li><li>レシート再印刷: 既発行分は引き続き閲覧できます</li><li>取消済みの会計には、新しい領収書発行や返金を重ねて行えません</li></ul><p><strong>この機能ではまだ取り消せないもの</strong>（取消ボタンが出ません）:</p><ul><li>分割会計</li><li>Stripe Connect など外部決済サービス経由のカード / QR 決済 — <strong>取消ではなく返金</strong>で処理します（テイクアウト章「オンライン決済テイクアウトの返金」を参照）</li><li>オンライン決済済みテイクアウト — 取消ではなく返金で処理します</li><li>返金済みの会計</li><li>緊急会計転記由来（手入力計上 / 注文紐付き転記）— 既存の緊急会計台帳から取消</li></ul><p><strong>注意</strong>:</p><ul><li>取消理由は必須・監査ログに残ります</li><li>同じ会計を二重に取り消さないよう、安全に処理されます</li><li>現金会計ではレジ上の残高は自動調整されますが、<strong>お客様への現金返却は別途手渡しで行ってください</strong></li></ul><hr><h3 id="注文紐付きの緊急会計転記も取り消せます" tabindex="-1">注文紐付きの緊急会計転記も取り消せます <a class="header-anchor" href="#注文紐付きの緊急会計転記も取り消せます" aria-label="Permalink to &quot;注文紐付きの緊急会計転記も取り消せます&quot;">​</a></h3><p>「売上へ転記する」（青ボタン）で通常会計に反映した記録も、後から取り消せるようになりました。</p><p><strong>操作手順</strong>:</p><ol><li>緊急会計台帳で対象の行をクリック</li><li>「売上転記」セクションに <strong>「緊急会計転記を取り消す」</strong> ボタン（オレンジ色）が表示される</li><li><strong>取消理由（必須）</strong> を入力</li><li>「緊急会計転記を取り消す」を押す → 確認ダイアログ → 取消実行</li></ol><p><strong>取消後の挙動</strong>:</p><ul><li>取引ジャーナル: 「取消済み」バッジ</li><li>レジ分析 &gt; 現金売上 / 期待残高: 現金返却分の調整記録が自動で入り、期待残高との差分は 0 になります</li><li>レジ分析 &gt; 外部分類別: voucher 等の集計から除外</li><li>緊急会計台帳: 「✗ 取消済み」バッジ + 取消日時 / 理由</li></ul><p><strong>手入力計上の取消と異なる点</strong>:</p><ul><li><strong>売上レポート（注文ベース集計）に「残ります」</strong>。通常会計と同じく「会計済み注文」として表示されます</li><li><strong>回転率レポートにも残ります</strong></li><li><strong>テーブル状態は戻りません</strong>。お客さんが退店済み・卓クローズ済みの後で取り消す前提です</li><li><strong>QR コードは元に戻りません</strong>。新しいお客様が座る前に、通常の卓オープン手順で再開してください</li></ul><p><strong>いつ使うか</strong>:</p><ul><li>外部端末控えとの不一致が後から判明したとき</li><li>誤って二重に転記してしまったとき</li><li>本来 <code>other_external</code> で分類すべきだったが先に <code>external_card</code> で転記してしまったとき（取消後に正しい分類で再転記）</li></ul><p><strong>いつ使わないか</strong>:</p><ul><li>通常会計（POS レジから直接会計したもの）→ 取引ジャーナル（取引履歴パネル）の「<strong>会計取消</strong>」ボタンから取り消します（§「通常会計も取り消せます」参照）。本ボタン（緊急会計転記の取消）ではありません。</li><li>営業中で次のお客さんが座っている卓 → ❌ <strong>テーブルセッションは戻らない</strong>ので、運用上の問題が発生</li></ul><p><strong>注意</strong>:</p><ul><li>取消済の注文は売上集計から自動で除外されます</li><li>取消理由は必須で記録に残ります</li><li>同じ会計を二重に取り消さないよう、安全に処理されます</li></ul><h3 id="手入力計上は取り消せます" tabindex="-1">手入力計上は取り消せます <a class="header-anchor" href="#手入力計上は取り消せます" aria-label="Permalink to &quot;手入力計上は取り消せます&quot;">​</a></h3><p>誤って「売上として計上する（手入力）」を押してしまった場合、<strong>管理者が後から取り消せます</strong>。</p><p><strong>操作手順</strong>:</p><ol><li>緊急会計台帳で対象の行をクリック（詳細モーダル）</li><li>「売上転記」セクションの下に <strong>「手入力計上を取り消す」</strong> ボタン（赤）が出る</li><li><strong>取消理由（必須）</strong> を入力</li><li>「手入力計上を取り消す」を押す → 確認ダイアログ → 取消実行</li></ol><p><strong>取消後の挙動</strong>:</p><ul><li>取引ジャーナル: 「取消済み」バッジが付く（行自体は残る）</li><li>レジ分析 &gt; 外部分類別: 商品券や振込などの集計から除外されます</li><li>レジ分析 &gt; 現金売上 / 期待残高: 現金の場合は返却分が反映され、期待残高との差が合うようになります</li><li>台帳: 緊急会計記録には「取消済み」バッジが付く、取消日時と理由が表示される</li></ul><p><strong>この「手入力計上の取消」では取り消せないもの</strong>（それぞれ別の経路で取り消せます）:</p><ul><li>注文紐付きで転記された通常会計（売上として計上する青いボタン経由）→ §「注文紐付きの緊急会計転記も取り消せます」</li><li>通常の POS レジで会計した payments → §「通常会計も取り消せます」（POS レジ &gt; 取引履歴の「会計取消」ボタン）</li><li>❌ 取消そのものの取り消し（= 再計上）は全系統で不可</li></ul><p><strong>注意</strong>:</p><ul><li>取消理由は必須です</li><li><strong>同じ記録を 2 回取り消そうとしても安全です</strong>（2 回目は何もせず成功扱い）</li><li>取消操作は<strong>元に戻せません</strong>。外部端末控えと金額を必ず再確認してから押してください</li></ul><h3 id="手入力売上は売上レポートには出ません" tabindex="-1">手入力売上は売上レポートには出ません <a class="header-anchor" href="#手入力売上は売上レポートには出ません" aria-label="Permalink to &quot;手入力売上は売上レポートには出ません&quot;">​</a></h3><p>管理者が台帳から「<strong>売上として計上する（手入力）</strong>」を押した記録は、以下に反映されます。</p><table tabindex="0"><thead><tr><th>画面</th><th>反映</th></tr></thead><tbody><tr><td>取引ジャーナル</td><td>✅ 出ます</td></tr><tr><td>レジ分析 &gt; レジログ・現金売上・期待残高</td><td>✅ 現金の手入力だけ反映</td></tr><tr><td>レジ分析 &gt; 外部分類別（商品券・ポイント充当等）</td><td>✅ 外部分類済みは反映</td></tr><tr><td><strong>売上レポート</strong></td><td>❌ <strong>出ません</strong></td></tr><tr><td>領収書</td><td>△ 明細が入っている記録のみ発行可能</td></tr><tr><td>返金（レジ画面）</td><td>❌ 構造上システム返金できません。手渡し返金 or 外部端末返金で運用</td></tr></tbody></table><p><strong>大事なポイント</strong>:</p><ul><li>売上レポート（注文ベース集計）には出ないため、<strong>手入力売上を含めた日次売上の確認はレジ分析タブを併用</strong>してください</li><li>計上ボタンを押す前に、外部端末の控えと金額が合っているかを必ず確認してください</li></ul><h3 id="その他外部決済は分類を選んでください" tabindex="-1">その他外部決済は分類を選んでください <a class="header-anchor" href="#その他外部決済は分類を選んでください" aria-label="Permalink to &quot;その他外部決済は分類を選んでください&quot;">​</a></h3><p>「その他外部決済」を選んだ場合、<strong>5 つの分類から必ず 1 つ選択</strong>してください。未選択のまま記録ボタンを押しても止まります。</p><table tabindex="0"><thead><tr><th>分類</th><th>いつ使うか</th></tr></thead><tbody><tr><td><strong>商品券</strong></td><td>紙の商品券、電子ギフト券、クーポン券を使ったとき</td></tr><tr><td><strong>事前精算</strong></td><td>予約金、コース前金、事前に店側で入金確認済みの金額を充当するとき</td></tr><tr><td><strong>店舗判断</strong></td><td>店長承認で通常会計とは別扱いにする特殊処理</td></tr><tr><td><strong>ポイント充当</strong></td><td>店舗独自ポイントで全額または一部を相殺したとき</td></tr><tr><td><strong>その他</strong></td><td>上記に当てはまらない特殊ケース (メモ欄に詳細を残す)</td></tr></tbody></table><p><strong>どれに当てはまるかわからないとき</strong>:</p><ul><li>最初の 4 つに当てはまりそうならそれを選ぶ</li><li>どうしても当てはまらない場合だけ「その他」を選び、<strong>メモ欄</strong> に理由を書く</li><li>台帳を確認する管理者が後追いで判断できるように詳細を残すのが安全です</li></ul><p><strong>注意</strong>:</p><ul><li>選んだ分類は、台帳表示と管理者確認のために使われます</li><li>以前に登録した記録は「その他外部（未分類）」と表示される場合があります</li></ul><h3 id="緊急レジの-pin-は任意です" tabindex="-1">緊急レジの PIN は任意です <a class="header-anchor" href="#緊急レジの-pin-は任意です" aria-label="Permalink to &quot;緊急レジの PIN は任意です&quot;">​</a></h3><p>緊急レジの「担当スタッフ PIN」欄は <strong>任意</strong> です。空欄でも緊急記録は残せます。</p><p><strong>PIN 欄の使い方</strong>:</p><ul><li>スタッフ本人の PIN を入力して記録 → 台帳 PIN 列が「<strong>✓ 確認済</strong>」（緑）になります</li><li>空欄のまま記録 → 台帳 PIN 列は「<strong>入力なし</strong>」（グレー）になります</li><li>間違った PIN を入力 → 台帳 PIN 列は「<strong>入力不一致</strong>」（オレンジ）になります</li><li>古い記録 (2026-04-20 以前) → 台帳 PIN 列は「<strong>未確認</strong>」（グレー） のままになります</li></ul><p><strong>「確認済」と「自己申告」の違い</strong>:</p><ul><li><strong>確認済</strong> = PIN 検証が通り、担当スタッフを確認できている状態</li><li><strong>自己申告</strong> = 担当欄にユーザー名は入っているが、PIN 検証なしでクライアントが自己報告したもの。台帳上で「担当」列に <code>(自己申告) 〇〇</code> と表示され、紐付け保証はありません</li></ul><p>PIN を運用したい場合はオーナーダッシュボード「スタッフ管理」タブで各スタッフに PIN を事前登録 + 勤怠打刻しておいてください。</p><h3 id="管理者の判断を記録する" tabindex="-1">管理者の判断を記録する <a class="header-anchor" href="#管理者の判断を記録する" aria-label="Permalink to &quot;管理者の判断を記録する&quot;">​</a></h3><p>manager / owner は緊急会計台帳の詳細モーダルから <strong>判断結果</strong> を記録できます。</p><p><strong>記録できる判断 (4 種類)</strong>:</p><table tabindex="0"><thead><tr><th>ボタン</th><th>意味</th><th>note</th></tr></thead><tbody><tr><td><strong>有効確認</strong></td><td>この緊急会計は正しい会計記録と確認した</td><td>任意</td></tr><tr><td><strong>重複扱い</strong></td><td>通常会計 / 別の緊急会計と重複していたため売上計上対象外</td><td><strong>必須</strong></td></tr><tr><td><strong>無効扱い</strong></td><td>誤入力・テスト・無効記録</td><td><strong>必須</strong></td></tr><tr><td><strong>保留にする</strong></td><td>まだ判断できない (外部端末の日締め待ち等)</td><td>任意</td></tr></tbody></table><p><strong>操作手順</strong>:</p><ol><li>緊急会計台帳で対象の行をクリック → 詳細モーダルが開く</li><li>下部の「管理者解決」エリアで note を入力 (重複扱い / 無効扱いは必須)</li><li>ボタンをクリック → 確認ダイアログ → 記録</li></ol><div class="warning custom-block"><p class="custom-block-title">売上レポートには反映されません</p><ul><li><strong>「有効確認」を記録しても、売上レポートには自動で反映されません</strong></li><li>管理者判断は台帳に残りますが、売上集計への自動反映は行われません</li><li>店舗の日次売上に緊急会計を含める場合は、外部決済端末の控えとあわせて管理してください</li></ul></div><div class="tip custom-block"><p class="custom-block-title">同じ判断の再送はエラーになりません</p><ul><li>同じ判断を誤って 2 回押しても「既に記録済み」として正常に処理されます</li><li>ただし<strong>異なる判断に変更する操作はできません</strong>。変更したい場合は POSLAサポートへご相談ください</li></ul></div><h3 id="売上へ転記する" tabindex="-1">売上へ転記する <a class="header-anchor" href="#売上へ転記する" aria-label="Permalink to &quot;売上へ転記する&quot;">​</a></h3><p>2026-04-20 以降、<strong>「有効確認」済みの緊急会計は、管理者が「売上へ転記」ボタンを押すと通常の売上に計上されます</strong>。</p><p><strong>前提条件</strong> (すべて満たすとき転記ボタンが出ます):</p><ul><li>管理者解決が「有効確認 (confirmed)」</li><li>まだ転記していない</li><li>同期失敗ではない</li><li>対象の注文が 1 件以上ある</li><li>支払方法が「その他外部決済」ではない (現金 / 外部カード / 外部 QR のみ)</li></ul><p><strong>操作手順</strong>:</p><ol><li>緊急会計台帳で有効確認済みの行を開く</li><li>詳細モーダル下部の「売上転記」ブロックに「売上へ転記する」ボタンが表示される</li><li>メモ (任意) を入力</li><li>ボタンを押すと確認ダイアログで「合計・支払方法・テーブル」が表示される</li><li><strong>外部決済端末の控えと金額・承認番号が一致することを必ず確認</strong></li><li>確定 → 通常の売上記録として登録され、売上レポート・レジ締めに反映</li></ol><p><strong>転記後の扱い</strong>:</p><ul><li>詳細モーダルに「✓ 転記済み」と表示</li><li>通常の売上レポートで「緊急会計由来の売上」として集計される</li><li>同じ緊急会計に対して再度ボタンを押しても二重転記されません</li></ul><div class="danger custom-block"><p class="custom-block-title">転記取消はまだできません</p><ul><li>一度「売上へ転記」した緊急会計は、その場では取り消せません</li><li>誤転記した場合は POSLAサポートへご相談ください</li><li>転記前の外部端末控えとの突合を必ず行ってください</li></ul></div><div class="tip custom-block"><p class="custom-block-title">支払方法の違い</p><ul><li><strong>現金</strong>: 現金残高と一致する想定 → 通常レポートで「現金売上」に計上</li><li><strong>外部カード端末</strong>: 通常レポートで「カード売上」に計上</li><li><strong>外部 QR / 電子マネー</strong>: 通常レポートで「QR 売上」に計上</li><li><strong>その他外部決済</strong>: 転記ボタンは表示されません</li></ul></div><h3 id="手入力モードの売上反映" tabindex="-1">手入力モードの売上反映 <a class="header-anchor" href="#手入力モードの売上反映" aria-label="Permalink to &quot;手入力モードの売上反映&quot;">​</a></h3><p>緊急会計の「手入力モード」(テーブル未選択で記録した会計) は、<strong>現時点で売上転記できません</strong>。</p><p>理由: 注文と紐づかない手入力の会計は、通常の売上記録へ自動反映しにくいためです。</p><p>対応:</p><ul><li>それまでは、手入力モードの緊急会計は <strong>POSLAサポートへご相談の上で対応</strong> してください</li></ul><h3 id="管理者が未同期会計がある端末を扱う時の注意" tabindex="-1">管理者が未同期会計がある端末を扱う時の注意 <a class="header-anchor" href="#管理者が未同期会計がある端末を扱う時の注意" aria-label="Permalink to &quot;管理者が未同期会計がある端末を扱う時の注意&quot;">​</a></h3><p>スタッフが未同期件数バッジを「!N」表示 (要確認あり) と報告してきた場合:</p><ol><li>端末の 🔴 → 「未同期会計一覧」で状態を確認</li><li>pending_sync / syncing / failed が残っていれば通信復帰を促す</li><li>要確認の会計があれば、管理画面の「緊急会計台帳」で精査</li><li>端末のブラウザ内保存データを<strong>絶対に消さない</strong>よう、スタッフに再周知</li></ol><h3 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h3><p><strong>Q. 緊急レジで記録した会計は、自動的に売上レポートに乗りますか？</strong> A. いいえ。まずは台帳に保存され、必要に応じて管理者が確認・対応します。</p><p><strong>Q. 同じテーブルで同じ会計を 2 回記録してしまったら？</strong> A. 各緊急会計には端末内で一意の番号が付くため、同じ記録ボタンを連打しても二重登録はされません。ただし手順自体を 2 回繰り返した場合は 2 件記録されます。未同期一覧で確認し、不要な方を管理者に相談してください。</p><p><strong>Q. 複数端末で同じテーブルを同時に緊急会計したら？</strong> A. 同じ注文が重複して記録された可能性があるとして「要確認」表示になります。管理者が内容を確認してください。</p><p><strong>Q. 外部端末の控え番号を間違えて記録してしまった</strong> A. 現時点では緊急会計の修正はできません。メモ欄に訂正情報を書き、管理者へ連絡してください。</p><p><strong>Q. カード番号を入力したい</strong> A. <strong>入力しないでください</strong>。POSLA の緊急レジではカード情報を扱いません。カード決済は必ず外部端末で完了し、その控え番号のみを記録してください。</p>',160)])])}const u=l(a,[["render",n]]);export{c as __pageData,u as default};
